parameters.jsCode:
// AIの出力（JSON文字列）をパースして、各フィールドを取り出す
const raw = $input.first().json.output;
const cleaned = String(raw).replace(/^```json\n?|^```\n?|\n?```$/g, '').trim();
let p;
try {
  p = JSON.parse(cleaned);
} catch (e) {
  p = {};
}
return [{ json: {
  now: p.now || new Date().toLocaleDateString('ja-JP'),
  title: p.title || '',
  client_name: p.client_name || '',
  key_person: p.key_person || '',
  priority: p.priority || '',
  priority_reason: p.priority_reason || '',
  summary: p.summary || '',
  sales_phase: p.sales_phase || '',
  probability: p.probability || '',
  next_action: p.next_action || '',
  follow_up_date: p.follow_up_date || ''
} }];

